};

export default HelloWorld;

def count_odd_elements(lst):
    if not lst:
        raise IndexError("List is empty")

    odd_count = 0
    for element in lst:
        if not isinstance(element, int):
            raise ValueError("List contains non-integer elements")
        if element % 2 != 0:
            odd_count += 1

    return odd_count

# Example usage:
try:
    lst = [1, 2, 3, 4, 5]
    odd_count = count_odd_elements(lst)
    print(f"Number of odd elements: {odd_count}")
except IndexError as e:
    print(f"Error: {str(e)}")
except ValueError as e:
    print(f"Error: {str(e)}")

