function getCurrentURL() {
  var anchor = document.createElement('a');
  anchor.href = '';
  var url = anchor.href;

  // Get protocol
  var protocol = url.substring(0, url.indexOf(':'));

  // Get hostname
  var hostname = url.substring(url.indexOf('//') + 2, url.indexOf('/', url.indexOf('//') + 2));

  // Get path
  var path = url.substring(url.indexOf('/', url.indexOf('//') + 2));

  // Get query parameters
  var query = url.substring(url.indexOf('?'));

  // Get fragment identifier
  var fragment = url.substring(url.indexOf('#'));

  // Encode special characters
  url = encodeURI(url);
  protocol = encodeURI(protocol);
  hostname = encodeURI(hostname);
  path = encodeURI(path);
  query = encodeURI(query);
  fragment = encodeURI(fragment);

  // Build the formatted URL
  var formattedURL = protocol + '://' + hostname + path + query + fragment;

  // Display the formatted URL on the webpage
  var urlElement = document.getElementById('url');
  urlElement.textContent = formattedURL;
}

// Call the function to get and display the current URL
getCurrentURL();
